module.m4.body:
DDL komutları veritabanı yapısını tanımlar.

CREATE TABLE yeni bir tablo oluşturur:
CREATE TABLE users (id INTEGER PRIMARY KEY, name TEXT);

ALTER TABLE mevcut bir tabloya sütun ekler:
ALTER TABLE users ADD COLUMN email TEXT;

DROP TABLE tabloyu ve içindeki tüm veriyi kalıcı olarak siler:
DROP TABLE users;

module.m7.body:
Alt sorgular hesaplanan listeleri veya tek bir değeri kullanarak filtreleme yapar.

IN: sütun değeri alt sorgu sonucunda varsa satırı döndürür.
SELECT name FROM customers WHERE id IN (SELECT customer_id FROM orders);

Skaler: tek bir hesaplanan değerle karşılaştırma.
SELECT name FROM customers WHERE id = (SELECT customer_id FROM orders ORDER BY total DESC LIMIT 1);

EXISTS: alt sorgu en az bir satır bulursa true döner.
SELECT name FROM customers WHERE EXISTS (SELECT 1 FROM orders WHERE orders.customer_id = customers.id);
